+            magic: NATIVE_FILE_MAGIC,
+            fd,
+            buffer_base: ptr::null_mut(),
+            buffer_pos: ptr::null_mut(),
+            buffer_end: ptr::null_mut(),
+            buffer_size: 0,
+            flags,
+            buf_mode,
+            _pad0: [0; 3],
+            ungetc_buf: -1, // empty
+            _pad1: [0; 6],
+            offset: 0,
+            vtable: ptr::null(),
+            lock: 0,
+            _pad2: [0; 4],
+            _reserved: [0; 136],
+        }
+    }
